#include <iomanip>
#include <iostream>
#include <string>
#include <string_view>

class Vehicle
{
    std::string m_make;
    int m_year{};

public:
    Vehicle(std::string_view make, int year)
        : m_make{ make }, m_year{ year }
    {
    }

    std::string_view getMake() const { return m_make; }
    int getYear() const { return m_year; }
};

class Car : public Vehicle
{
    int m_numDoors{};

public:
    Car(std::string_view make, int year, int numDoors)
        : Vehicle{ make, year }, m_numDoors{ numDoors }
    {
    }

    int getNumDoors() const { return m_numDoors; }
};

class Truck : public Vehicle
{
    double m_payloadTons{};

public:
    Truck(std::string_view make, int year, double payloadTons)
        : Vehicle{ make, year }, m_payloadTons{ payloadTons }
    {
    }

    double getPayloadTons() const { return m_payloadTons; }
};

int main()
{
    std::string carMake{};
    int carYear{};
    int numDoors{};
    std::cin >> carMake >> carYear >> numDoors;

    std::string truckMake{};
    int truckYear{};
    double payloadTons{};
    std::cin >> truckMake >> truckYear >> payloadTons;

    Car car{ carMake, carYear, numDoors };
    Truck truck{ truckMake, truckYear, payloadTons };

    std::cout << "Car: " << car.getMake() << " (" << car.getYear()
              << "), " << car.getNumDoors() << " doors\n";
    std::cout << std::fixed << std::setprecision(1);
    std::cout << "Truck: " << truck.getMake() << " (" << truck.getYear()
              << "), " << truck.getPayloadTons() << "t payload\n";

    return 0;
}
